import React, { useEffect, useState } from 'react';
import { data } from './data';
import { data1 } from './data';
import Navbarr from './Navbar';
import axios from 'axios';
import Swal from 'sweetalert2';
import { useParams } from 'react-router-dom';
import useItemIdStore from './zustandStore';

const Update = () => {
    const storedItemId = useItemIdStore((state) => state.itemId);

    const [Annonces, setAnnonces] = useState([]);
    const [Categorie, setCategorie] = useState('');
    const [Ville, setVille] = useState('');
    const [Plus, setPlus] = useState([]);
    const [plusCategorie, setplusCategorie] = useState('');
    const [Secteurs, setSecteurs] = useState([]);
    const [Secteur, setSecteur] = useState('');
    const [Telephone, setTelephone] = useState('');
    const [Etat, setEtat] = useState('');
    const [Prix, setPrix] = useState('');
    const [Titre, setTitre] = useState('');
    const [TexteAnnonce, setTexteAnnonce] = useState('');
    const [Images, setImages] = useState([]);
    const [Video, setVideo] = useState(null);
    const [uploadProgress, setUploadProgress] = useState(0);

    useEffect(() => {
        const p = data.find(d => d.categorie === Categorie);
        setPlus(p?.plus || []);
    }, [Categorie]);

    useEffect(() => {
        const s = data1.find(d => d.Ville === Ville);
        setSecteurs(s?.Secteur || []);
    }, [Ville]);

    useEffect(() => {
        const fetchData = async () => {
            try {
                const response = await axios.get(`http://127.0.0.1:5000/annonce/${storedItemId}`);
                setAnnonces(response.data);
                const annonce = response.data;
                setCategorie(annonce.categorie);
                setVille(annonce.ville);
                setplusCategorie(annonce.plusCategorie);
                setSecteur(annonce.secteur);
                setTelephone(annonce.NumeroTele);
                setEtat(annonce.Etat);
                setPrix(annonce.Prix);
                setTitre(annonce.titre);
                setTexteAnnonce(annonce.TexteAnnonce);
                setImages(annonce.images);
                setVideo(annonce.video);
            } catch (error) {
                console.error("Error fetching data:", error);
                window.location.replace('/')
            }
        };
        fetchData();
    }, []);

    const handleImageChange = (e) => {
        const selectedFiles = e.target.files;
        if (selectedFiles.length <= 8) {
            const imagesArray = Array.from(selectedFiles);
            setImages(imagesArray);
        } else {
            setImages([])
            alert('You can only select up to 8 files.');
        }
    };

    const valid = async () => {
        const emptyFields = [Categorie, Ville, Secteur, Telephone, Etat, Prix, Titre, TexteAnnonce].filter(field => field === '').length > 0;
        if (emptyFields) {
            Swal.fire({ 
                icon: "error",
                title: "Oops…", 
                text: "Please fill in all required fields.", 
            }); 
            return;
        }

        try {
            const formData = new FormData();

            if (Video) {
                formData.append('video', Video);
            }

            Images.forEach(image => {
                formData.append('images', image);
            });

            formData.append('data', JSON.stringify({
                "categorie": Categorie,
                "plusCategorie": plusCategorie,
                "ville": Ville,
                "secteur": Secteur,
                "NumeroTele": Telephone,
                "Etat": Etat,
                "Prix": Prix,
                "titre": Titre,
                "TexteAnnonce": TexteAnnonce,
            }));
            const config = {
                headers: {
                    'Content-Type': 'multipart/form-data'
                },
                onUploadProgress: progressEvent => {
                    const percentCompleted = Math.round((progressEvent.loaded * 100) / progressEvent.total);
                    setUploadProgress(percentCompleted);
                }
            };
            const response = await axios.put(`http://127.0.0.1:5000/annonce/update/${storedItemId}`, formData, config); 

            if (response){
                Swal.fire({
                    title: "Good job!",
                    text: "Updated with success!",
                    icon: "success"
                });
                setTimeout(() => window.location.replace('http://localhost:3000/'), 2000);
                console.log('Response:', response);
            }

        } catch (error) {
            console.error('Error fetching data:', error);
        }
    }

    return (
        <>
            <Navbarr />
            <div className='form-annonce mt-5'>
                <div className='card'>
                    <div className='card-body'>
                        <section encType={'multipart/form-data'}>
                            <p className='ff-3 h4 mb-3'>Qu'annoncez-vous aujourd'hui ?</p>
                            <div className="form-group">
                                <label className='ff-3'>Email :</label><br />
                                <input type="text"  className='w-75' <PRESIDIO_ANONYMIZED_EMAIL_ADDRESS>'} disabled/><br/>
                                <label className='ff-3'>Password :</label><br />
                                <input type="text"  className='w-75' value={'password'} disabled/>
                            </div>
                            <div className="form-group">
                                <label className='ff-3'>Catégorie :</label><br />
                                <select value={Categorie} onChange={(e)=>setCategorie(e.target.value)} className='w-75 form-select form-select-lg'>
                                    <option >-select Catégorie -</option>
                                    {data.map((d,i)=>(<option key={i} value={d.categorie}>{d.categorie}</option>))}
                                </select><br />

                            </div>
                            {Plus && Plus.length > 0 ? (
                                <>
                                    <div className="form-group">
                                        <label className='ff-3'>Plus Catégorie :</label><br />
                                        <select className='w-75'onChange={(e)=>setplusCategorie(e.target.value)} value={plusCategorie}>
                                             <option >-select Catégorie -</option>   
                                            {Plus.map((d,i)=>(<option key={i} value={d}>{d}</option>))}
                                        </select>
                                    </div>
                                </>
                            ) : null}
                            <div className="form-group">
                                <label className='ff-3'>Adresse principale de l'annonce :</label><br />
                                <select name="Adresse" onChange={(e)=>setVille(e.target.value)} value={Ville} className='w-75'>
                                    <option >-select Ville -</option>
                                    {data1.map((d,i)=>(<option key={i} value={d.Ville}>{d.Ville}</option>))}
                                </select><br />

                            </div>
                            {Ville && Secteurs.length > 0 ? (
                                <>
                                    <div className="form-group">
                                        <label className='ff-3'>Secteur :</label><br />
                                        <select className='w-75'value={Secteur} onChange={e=>setSecteur(e.target.value)}>
                                            <option >-select Secteur -</option>
                                            {Secteurs.map((d,i)=>(<option key={i} value={d}>{d}</option>))}
                                        </select>
                                    </div>
                                </>
                            ) : null}
                            <div className="form-group">
                                <label className='ff-3'>Select Numero de Telephone :</label><br />
                                <select onChange={(e)=>setTelephone(e.target.value)} value={Telephone} className='w-75'>
                                    <option >-select-</option>
                                    <option value="(+212) 0660728639">(+212) 0660728639</option>
                                    <option value="(+212) 0634343021">(+212) 0634343021</option>
                                </select>
                            </div>
                            <div className="form-group">
                                <select onChange={(e)=>setEtat(e.target.value)} value={Etat} className='w-75'>
                                    <option  >-État-</option>
                                    <option value="Neuf">Neuf</option>
                                    <option value="Très bon">Très bon</option>
                                    <option value="Bon">Bon</option>
                                    <option value="Correct">Correct</option>
                                    <option value="Endommagé">Endommagé</option>
                                    <option value="Pour Pièces">Pour Pièces</option>
                                </select>
                            </div>
                            <div className="form-group">
                                <label className='ff-3'>Prix :</label><br />
                                <input type="number" onChange={(e)=>setPrix(e.target.value)} defaultValue={Prix} name="prix" className='w-75' placeholder='Prix...'/>
                            </div>
                            <div className="form-group">
                                <label className='ff-3'>Titre de l'annonce :</label><br />
                                <input type="text" onChange={(e)=>setTitre(e.target.value)} value={Titre} name="Titre" className='w-75' placeholder="Titre de l'annonce...."/>
                            </div>
                            <div className="form-group">
                                <label className='ff-3'>Texte de l'annonce :</label><br />
                                <textarea onChange={(e)=>setTexteAnnonce(e.target.value)} defaultValue={TexteAnnonce} name="texta" cols="30" rows="10" className='w-75'></textarea>
                            </div>
                            <div className="form-group">
                                <label className='ff-3'>Images :</label><br />
                                <input className="form-control form-control-lg" type='file' multiple onChange={handleImageChange} accept="image/" /><br />
                                {Images.length > 0 && typeof Images[0] === 'string' ? (
                                    <div className="image-previews">
                                        {Images.map((image, index) => (
                                            <img key={index} src={`uploads/${image}`} alt="Preview" style={{ width: '100px', height: '100px' }} />
                                        ))}
                                    </div>
                                ) : (
                                    <div className="image-previews">
                                        {Images.map((image, index) => (
                                            <img key={index} src={URL.createObjectURL(image)} alt="Preview" style={{ width: '100px', height: '100px' }} />
                                        ))}
                                    </div>
                                )}
                                <label htmlFor="videoUpload" className="form-label">Video :</label>
                                <input id="videoUpload" accept="video/"  className="form-control form-control-lg" type="file"  onChange={(e) => setVideo(e.target.files[0])} />
                                {Video && typeof Video === 'string' ? (
                                    <video width="320" height="240" controls>
                                        <source src={`uploads/${Video}`} type="video/mp4" />
                                        Your browser does not support the video tag.
                                    </video>
                                ) : (
                                    Video && (
                                        <video width="320" height="240" controls>
                                            <source src={URL.createObjectURL(Video)} type="video/mp4" />
                                            Your browser does not support the video tag.
                                        </video>
                                    )
                                )}

                            </div>

                            <button type="submit" className="btn btn-primary btn-lg" onClick={valid}>Update</button>
                        </section>
                    </div>
                </div>
            </div>
        </>
    );
}

export default Update;

Your React component for updating an announcement (or "annonce" in French) displays a form that allows a user to modify details of an existing announcement. It interacts with a backend server via Axios to fetch the current announcement details and then update those details. Here's an analysis and explanation of how your component works, along with some suggestions for improvement:

### Key Features:
1. **State Management**: You're using `useState` to manage the form fields and the uploaded images/video. This is a straightforward approach for handling form inputs in React.

2. **External Data Fetching**: Upon component mounting, you fetch the existing announcement details using the `useEffect` hook and `axios.get`, which is a good practice for initializing form values with external data.

3. **Form Submission**: The `valid` function, which you call on form submit, checks for empty required fields using a sweet alert to inform the user if any required field is missing. Then, it constructs a `FormData` object to send both the text fields and files to the server.

4. **Progress Tracking**: You've implemented progress tracking for file uploads. This enhances user experience by providing feedback during file upload operations.

5. **Zustand for State Sharing**: You use Zustand (`useItemIdStore`) to share the state (in this case, the item ID) across components. This is a minimalist state management solution that fits React's functional components well.

### Suggestions for Improvement:
1. **Validate File Types**: Ensure you validate the types of files being uploaded on the client side for images and video to prevent unexpected file types from being submitted.

2. **Error Handling in Axios Requests**: While you catch errors in your Axios request, consider providing more detailed feedback to the user about the nature of the error instead of just redirecting or logging to console. This can improve the user's understanding of what went wrong.

3. **Conditional Rendering**: You've implemented conditional rendering for showing additional categories and sectors based on the selected `Categorie` and `Ville`. Make sure this logic precisely matches your application's requirements.

4. **File Previews**: You are showing previews for both images and video, which is excellent for user feedback. Consider adding a way for users to remove selected files before uploading if they change their mind.

5. **Accessibility**: Remember to add `alt` attributes to your image tags that describe the image content for screen readers and users who disable images.

6. **Code Organization**: As your component grows, you might find it beneficial to split this large component into smaller subcomponents, like form inputs or file uploaders, to make the code more manageable and reusable.

7. **Security**: Ensure your backend handles uploaded files securely, checking for maximum file sizes, scanning for malware, and validating file types to prevent security vulnerabilities.

8. **Use of Environment Variables**: For API URLs (`http://127.0.0.1:5000/annonce`${storedItemId}`), consider using environment variables for easier configuration across different environments (development, staging, production).

